const items = $input.all();

if (!items.length) {
  return [{ json: { skip: true, count: 0 } }];
}

const proposals = items.map(i => i.json);

const proposalText = proposals.map(p =>
  'Proposal: ' + p.proposal_key + '\n' +
  'Produkt-Key: ' + p.product_key + '\n' +
  (p.product_name
    ? 'Produkt gefunden: ' + p.product_name + ' (aktiv: ' + p.product_active + ', Kategorie: ' + (p.category || '?') + ')'
    : 'PRODUKT NICHT IM KATALOG') + '\n' +
  'Grund: ' + (p.reason || '(kein Grund angegeben)') + '\n' +
  'Wartezeit: ' + p.days_pending + ' Tage'
).join('\n\n---\n\n');

const SYSTEM = `Du bist Assistent fuer ein Verkaufsautomaten-Unternehmen.
Bearbeite offene Rechnungsvorschlaege nach diesen Regeln:
- approve: Produkt existiert im Katalog (product_name vorhanden) UND ist aktiv UND der Grund ist klar
- reject: Produkt NICHT im Katalog UND Wartezeit > 21 Tage ODER Grund ist voellig unklar
- escalate: Alle anderen Faelle (neue Produkte, grosse Aenderungen, unsicher)
Antworte AUSSCHLIESSLICH als gueltiges JSON-Objekt:
{"decisions":[{"proposal_key":"...","action":"approve|reject|escalate","reason":"..."}]}`;

return [{ json: {
  skip: false,
  count: proposals.length,
  input_keys: proposals.map(p => p.proposal_key),
  claude_request_body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    system: SYSTEM,
    messages: [{
      role: 'user',
      content: proposals.length + ' offene Proposals (aelter als 14 Tage):\n\n' + proposalText +
        '\n\nBitte entscheide fuer jeden Proposal.'
    }]
  }
}}];

const claudeResp  = $input.first().json;
const prevData    = $('Code - Proposals formatieren').first().json;
const inputKeys   = prevData.input_keys || [];

// Claude-Antwort parsen
let decisions = [];
try {
  const raw  = claudeResp.content?.[0]?.text || '{}';
  const parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || '{}');
  decisions = parsed.decisions || [];
} catch(e) {
  decisions = [];
}

// Nur Schluesseln vertrauen die wirklich aus der DB kamen
const safeDecisions = decisions.filter(d => inputKeys.includes(d.proposal_key));

const approvals   = safeDecisions.filter(d => d.action === 'approve');
const rejections  = safeDecisions.filter(d => d.action === 'reject');
const escalations = safeDecisions.filter(d => d.action === 'escalate');

// Batch-UPDATE SQL bauen
let updateSql = '';
if (approvals.length + rejections.length > 0) {
  const cases = [
    ...approvals.map(d =>  "  WHEN proposal_key = '" + d.proposal_key.replace(/'/g,"''") + "' THEN 'approved'"),
    ...rejections.map(d => "  WHEN proposal_key = '" + d.proposal_key.replace(/'/g,"''") + "' THEN 'rejected'"),
  ].join('\n');
  const keys = [...approvals, ...rejections]
    .map(d => "'" + d.proposal_key.replace(/'/g,"''") + "'").join(',');
  updateSql = 'UPDATE automatenlager.product_change_proposals SET status = CASE\n' + cases +
    '\n  ELSE status END WHERE proposal_key IN (' + keys + ") AND status = 'pending'";
} else {
  updateSql = 'SELECT 1';  // Nichts zu tun
}

// E-Mail nur bei Eskalationen
const hasEscalations = escalations.length > 0;
const ts = new Date().toISOString();

const makeList = arr => arr.map(d =>
  '<li><strong>' + d.proposal_key + '</strong>: ' + (d.reason || '—') + '</li>'
).join('');

const emailBody = '<h2>Claude-Proposals Bericht</h2>' +
  (approvals.length   ? '<h3 style="color:green">Auto-Genehmigt (' + approvals.length + ')</h3><ul>' + makeList(approvals) + '</ul>' : '') +
  (rejections.length  ? '<h3 style="color:#c0392b">Auto-Abgelehnt (' + rejections.length + ')</h3><ul>' + makeList(rejections) + '</ul>' : '') +
  (escalations.length ? '<h3 style="color:#e67e22">Eskaliert — manuell pruefen (' + escalations.length + ')</h3><ul>' + makeList(escalations) + '</ul>' : '') +
  '<hr><p style="color:#888;font-size:12px">Claude-Proposals: ' + ts + '</p>';

return [{ json: {
  update_sql: updateSql,
  has_escalations: hasEscalations ? 'JA' : 'NEIN',
  approved_count:  approvals.length,
  rejected_count:  rejections.length,
  escalated_count: escalations.length,
  email_subject: '[Proposals] ' + escalations.length + ' offen — ' + approvals.length + ' ok, ' + rejections.length + ' abgelehnt',
  email_body: emailBody
}}];
